async (params, browser) => {
  // Open Threads profile
  await browser.open(`https://www.threads.net/@${params.username}`)

  // Wait for profile page to load
  await browser.waitForSelector('[class*=\'ProfileHeader\'], [class*=\'profile\'], header, [class*=\'UserProfile\']', 15000)

  // Let profile fully render
  await browser.wait(3000)

  // Scroll to load posts
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Extract profile data
  const result = await browser.evaluate(`const username = '' + params.username + ''; const nameEl = document.querySelector('[class*="ProfileHeader"] h1, [class*="profile"] h1, h1[dir="auto"], [class*="userName"], header h2'); const displayName = nameEl ? nameEl.textContent.trim() : username; const bioEl = document.querySelector('[class*="bio"], [class*="ProfileBio"], [class*="biography"], [class*="profile"] span[dir="auto"]'); let bio = ''; if (bioEl) { bio = bioEl.textContent.trim(); } else { const spans = document.querySelectorAll('span[dir="auto"]'); for (const span of spans) { const text = span.textContent.trim(); if (text.length > 20 && text !== displayName && !text.includes('followers') && !text.includes('threads')) { bio = text; break; } } } const followerEl = document.querySelector('[class*="follower"], [class*="Follower"], a[href*="followers"], [class*="count"]'); let followers = ''; if (followerEl) { followers = followerEl.textContent.trim(); } else { const allSpans = document.querySelectorAll('span'); for (const span of allSpans) { const text = span.textContent.trim().toLowerCase(); if (text.includes('follower')) { followers = text; break; } } } const profilePicEl = document.querySelector('img[alt*="profile"], img[alt*="' + username + '"], [class*="ProfilePic"] img, [class*="avatar"] img, header img'); const profilePic = profilePicEl ? profilePicEl.src : ''; const verifiedEl = document.querySelector('svg[aria-label*="Verified"], [class*="verified"], [class*="badge"]'); const isVerified = !!verifiedEl; const recentPosts = []; const postEls = document.querySelectorAll('[class*="ThreadItem"], article, div[role="article"], [data-pressable-container="true"]'); for (let i = 0; i < Math.min(postEls.length, 10); i++) { const el = postEls[i]; const contentEl = el.querySelector('[class*="text"], [class*="content"], [dir="auto"] span, [class*="TextContent"]'); let content = ''; if (contentEl) { content = contentEl.textContent.trim().substring(0, 200); } else { const spans = el.querySelectorAll('span[dir="auto"]'); for (const span of spans) { const text = span.textContent.trim(); if (text.length > content.length && text !== displayName && text !== username) content = text.substring(0, 200); } } const timeEl = el.querySelector('time, [class*="time"]'); const timestamp = timeEl ? (timeEl.getAttribute('datetime') || timeEl.textContent.trim()) : ''; const likesEl = el.querySelector('[class*="like"] span, [aria-label*="like"]'); const likes = likesEl ? (likesEl.getAttribute('aria-label') || likesEl.textContent.trim()) : ''; const postLink = el.querySelector('a[href*="/post/"], a[href*="/t/"]'); const postUrl = postLink ? (postLink.href.startsWith('http') ? postLink.href : 'https://www.threads.net' + postLink.getAttribute('href')) : ''; if (content) { recentPosts.push({ content: content, likes: likes, timestamp: timestamp, post_url: postUrl }); } } return { username: username, display_name: displayName, bio: bio, followers: followers, is_verified: isVerified, profile_pic: profilePic, recent_posts: recentPosts, profile_url: window.location.href }`)

  return result
}
